import React, { useState, useEffect } from 'react';
import './CinemaManagement.css';

const CinemaManagement = () => {
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCinema, setEditingCinema] = useState(null);
  const [viewingCinema, setViewingCinema] = useState(null);
  const [currentStep, setCurrentStep] = useState(1);
  const [errors, setErrors] = useState({});
  const [notification, setNotification] = useState({
    show: false,
    message: "",
    type: "success"
  });

  const [formData, setFormData] = useState({
    cinema_name: '',
    cinema_location: '',
    google_maps_location: '',
    contact_info: {
      phone: '',
      email: ''
    },
    ongoing_movies: {
      movie_1: { name: '', start_date: '', end_date: '', trailer_link: '' },
      movie_2: { name: '', start_date: '', end_date: '', trailer_link: '' },
      movie_3: { name: '', start_date: '', end_date: '', trailer_link: '' },
      movie_4: { name: '', start_date: '', end_date: '', trailer_link: '' }
    },
    upcoming_movies: {
      movie_1: { name: '', trailer_link: '' },
      movie_2: { name: '', trailer_link: '' }
    },
    movie_slot_pricing: {
      movie_1: { starting_price: 0, interval_price: 0, ending_price: 0 },
      movie_2: { starting_price: 0, interval_price: 0, ending_price: 0 },
      movie_3: { starting_price: 0, interval_price: 0, ending_price: 0 },
      movie_4: { starting_price: 0, interval_price: 0, ending_price: 0 }
    },
    is_active: true
  });

  const totalSteps = 7;

  const steps = [
    { id: 1, title: 'General Details', description: 'Basic cinema information' },
    { id: 2, title: 'Movie 1', description: 'First ongoing movie' },
    { id: 3, title: 'Movie 2', description: 'Second ongoing movie' },
    { id: 4, title: 'Movie 3', description: 'Third ongoing movie' },
    { id: 5, title: 'Movie 4', description: 'Fourth ongoing movie' },
    { id: 6, title: 'Upcoming Movies', description: 'Future releases' },
    { id: 7, title: 'Review & Submit', description: 'Final review' }
  ];

  // Fetch cinemas from API
  const fetchCinemas = async () => {
    try {
      setLoading(true);
      const response = await fetch('http://localhost:5000/api/cinemas');
      const data = await response.json();

      if (data.success) {
        setCinemas(data.data);
      } else {
        showNotification('Failed to fetch cinemas', 'error');
      }
    } catch (error) {
      console.error('Error fetching cinemas:', error);
      showNotification('Error fetching cinemas', 'error');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCinemas();
  }, []);

  const showNotification = (message, type = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => {
      setNotification({ ...notification, show: false });
    }, 5000);
  };

  const closeNotification = () => {
    setNotification({ ...notification, show: false });
  };

  // Header Component
  const CinemaHeader = () => {
    return (
      <header id="cinema-header">
        <div className="intro">
          <video 
            className="intro-video" 
            autoPlay 
            muted 
            loop 
            playsInline
          >
            <source src="/vid/background-video.mp4" type="video/mp4" />
            <source src="/vid/background-video.webm" type="video/webm" />
            Your browser does not support the video tag.
          </video>

          <div className="overlay">
            <div className="container">
              <div className="row">
                <div className="col-md-8 col-md-offset-2 intro-text">
                  <h1>
                    Cinema Management
                    <span></span>
                  </h1>
                  <p>
                    Manage your cinema locations, movie schedules, and advertisement slots. 
                    Create, update, and monitor all your cinema operations from one central dashboard.
                  </p>
                  <a
                    href="#cinema-cards"
                    className="btn btn-custom btn-lg page-scroll"
                  >
                    View Cinemas
                  </a>
                </div>
              </div>
            </div>
          </div>
        </div>
      </header>
    );
  };

  // Cinema Card Component
  const CinemaCard = ({ cinema }) => {
    const [showActions, setShowActions] = useState(false);

    const handleUpdate = (e) => {
      e.preventDefault();
      setEditingCinema(cinema);
      setFormData(cinema);
      setIsModalOpen(true);
      setCurrentStep(1);
    };

    const handleDelete = async (e) => {
      e.preventDefault();
      if (window.confirm(`Are you sure you want to delete ${cinema.cinema_name}?`)) {
        try {
          const response = await fetch(`http://localhost:5000/api/cinemas/${cinema._id}`, {
            method: 'DELETE'
          });
          const data = await response.json();

          if (data.success) {
            showNotification('Cinema deleted successfully', 'success');
            fetchCinemas();
          } else {
            showNotification('Failed to delete cinema', 'error');
          }
        } catch (error) {
          console.error('Error deleting cinema:', error);
          showNotification('Error deleting cinema', 'error');
        }
      }
    };

    const handleViewDetails = (e) => {
      e.preventDefault();
      setViewingCinema(cinema);
    };

    const getMovieCount = () => {
      let count = 0;
      if (cinema.ongoing_movies) {
        Object.keys(cinema.ongoing_movies).forEach(key => {
          if (cinema.ongoing_movies[key] && cinema.ongoing_movies[key].name) {
            count++;
          }
        });
      }
      return count;
    };

    const getUpcomingCount = () => {
      let count = 0;
      if (cinema.upcoming_movies) {
        Object.keys(cinema.upcoming_movies).forEach(key => {
          if (cinema.upcoming_movies[key] && cinema.upcoming_movies[key].name) {
            count++;
          }
        });
      }
      return count;
    };

    const formatDate = (dateString) => {
      if (!dateString) return 'N/A';
      return new Date(dateString).toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'short',
        day: 'numeric'
      });
    };

    const getStatusBadge = () => {
      return cinema.is_active ? (
        <span className="status-badge active">Active</span>
      ) : (
        <span className="status-badge inactive">Inactive</span>
      );
    };

    return (
      <div 
        className={`cinema-card ${!cinema.is_active ? "inactive" : ""}`}
        onMouseEnter={() => setShowActions(true)}
        onMouseLeave={() => setShowActions(false)}
      >
        <div className="meta">
          <div 
            className="photo" 
            style={{ 
              backgroundImage: `url(${cinema.image || '/images/cinema.jpg'})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center'
            }} 
          />
          <ul className="details">
            <li className="author">
              <a href="#" onClick={handleViewDetails}>
                {cinema.cinema_name}
              </a>
            </li>
            <li className="date">{formatDate(cinema.createdAt)}</li>
            <li className="tags">
              <ul>
                <li><span className="tag">{cinema.cinema_location}</span></li>
                <li><span className="tag">{getMovieCount()} Movies</span></li>
                <li><span className="tag">{getUpcomingCount()} Upcoming</span></li>
              </ul>
            </li>
          </ul>
        </div>
        <div className="description">
          <div className="card-header">
            <div className="card-date">
              <i className="fa fa-calendar"></i>
              <span>{formatDate(cinema.createdAt)}</span>
            </div>
            {getStatusBadge()}
          </div>

          <h1>{cinema.cinema_name}</h1>
          <h2>{cinema.cinema_location}</h2>

          <div className="cinema-stats">
            <div className="stat-item">
              <i className="fa fa-film"></i>
              <span>{getMovieCount()} Ongoing Movies</span>
            </div>
            <div className="stat-item">
              <i className="fa fa-clock-o"></i>
              <span>{getUpcomingCount()} Upcoming</span>
            </div>
            <div className="stat-item">
              <i className="fa fa-map-marker"></i>
              <span>{cinema.cinema_location}</span>
            </div>
          </div>

          <div className="cinema-movies">
            <h4>Current Movies:</h4>
            <div className="movie-list">
              {cinema.ongoing_movies && Object.keys(cinema.ongoing_movies).map((key, index) => {
                const movie = cinema.ongoing_movies[key];
                if (movie && movie.name) {
                  return (
                    <div key={index} className="movie-item">
                      <span className="movie-name">{movie.name}</span>
                      <span className="movie-dates">
                        {formatDate(movie.start_date)} - {formatDate(movie.end_date)}
                      </span>
                    </div>
                  );
                }
                return null;
              })}
            </div>
          </div>

          <div className="card-actions">
            <button 
              className="action-btn view-btn"
              onClick={handleViewDetails}
            >
              <i className="fa fa-eye"></i> View Details
            </button>

            <button 
              className="action-btn update-btn"
              onClick={handleUpdate}
            >
              <i className="fa fa-edit"></i> Update
            </button>

            <button 
              className="action-btn delete-btn"
              onClick={handleDelete}
            >
              <i className="fa fa-trash"></i> Delete
            </button>
          </div>
        </div>
      </div>
    );
  };

  // Validation functions
  const validateCinemaName = (name) => {
    if (!name || name.trim().length === 0) {
      return 'Cinema name is required';
    }
    if (name.trim().length < 2) {
      return 'Cinema name must be at least 2 characters';
    }
    return null;
  };

  const validateLocation = (location) => {
    if (!location || location.trim().length === 0) {
      return 'Cinema location is required';
    }
    if (location.trim().length < 5) {
      return 'Cinema location must be at least 5 characters';
    }
    return null;
  };

  const validateMovie = (movie, movieNumber) => {
    const errors = {};

    if (!movie.name || movie.name.trim().length === 0) {
      errors.name = `Movie ${movieNumber} name is required`;
    }

    if (!movie.start_date) {
      errors.start_date = `Movie ${movieNumber} start date is required`;
    }

    if (!movie.end_date) {
      errors.end_date = `Movie ${movieNumber} end date is required`;
    }

    if (movie.start_date && movie.end_date) {
      const startDate = new Date(movie.start_date);
      const endDate = new Date(movie.end_date);
      if (endDate <= startDate) {
        errors.end_date = `Movie ${movieNumber} end date must be after start date`;
      }
    }

    if (movie.trailer_link && movie.trailer_link.trim().length > 0) {
      const youtubeRegex = /^https?:\/\/(www\.)?(youtube\.com|youtu\.be)\/.+/;
      if (!youtubeRegex.test(movie.trailer_link)) {
        errors.trailer_link = `Movie ${movieNumber} trailer must be a valid YouTube URL`;
      }
    }

    return errors;
  };

  const validateCurrentStep = () => {
    const newErrors = {};

    if (currentStep === 1) {
      const nameError = validateCinemaName(formData.cinema_name);
      if (nameError) newErrors.cinema_name = nameError;

      const locationError = validateLocation(formData.cinema_location);
      if (locationError) newErrors.cinema_location = locationError;
    } else if (currentStep >= 2 && currentStep <= 5) {
      const movieKey = `movie_${currentStep - 1}`;
      const movie = formData.ongoing_movies[movieKey];
      const movieErrors = validateMovie(movie, currentStep - 1);
      Object.assign(newErrors, movieErrors);
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;

    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({
        ...prev,
        [parent]: {
          ...prev[parent],
          [child]: type === 'checkbox' ? checked : value
        }
      }));
    } else if (name.startsWith('ongoing_movies.') || name.startsWith('upcoming_movies.') || name.startsWith('movie_slot_pricing.')) {
      const parts = name.split('.');
      const movieKey = parts[1];
      const field = parts[2];

      setFormData(prev => ({
        ...prev,
        [parts[0]]: {
          ...prev[parts[0]],
          [movieKey]: {
            ...prev[parts[0]][movieKey],
            [field]: type === 'checkbox' ? checked : value
          }
        }
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: type === 'checkbox' ? checked : value
      }));
    }

    // Clear error when user starts typing
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: null }));
    }
  };

  const handleNext = () => {
    if (validateCurrentStep()) {
      setCurrentStep(prev => Math.min(prev + 1, totalSteps));
    }
  };

  const handlePrevious = () => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  };

  const handleSubmit = async () => {
    try {
      const url = editingCinema 
        ? `http://localhost:5000/api/cinemas/${editingCinema._id}`
        : 'http://localhost:5000/api/cinemas';

      const method = editingCinema ? 'PUT' : 'POST';

      const response = await fetch(url, {
        method,
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (data.success) {
        showNotification(
          editingCinema ? 'Cinema updated successfully!' : 'Cinema created successfully!',
          'success'
        );
        setIsModalOpen(false);
        setEditingCinema(null);
        setFormData({
          cinema_name: '',
          cinema_location: '',
          google_maps_location: '',
          contact_info: { phone: '', email: '' },
          ongoing_movies: {
            movie_1: { name: '', start_date: '', end_date: '', trailer_link: '' },
            movie_2: { name: '', start_date: '', end_date: '', trailer_link: '' },
            movie_3: { name: '', start_date: '', end_date: '', trailer_link: '' },
            movie_4: { name: '', start_date: '', end_date: '', trailer_link: '' }
          },
          upcoming_movies: {
            movie_1: { name: '', trailer_link: '' },
            movie_2: { name: '', trailer_link: '' }
          },
          movie_slot_pricing: {
            movie_1: { starting_price: 0, interval_price: 0, ending_price: 0 },
            movie_2: { starting_price: 0, interval_price: 0, ending_price: 0 },
            movie_3: { starting_price: 0, interval_price: 0, ending_price: 0 },
            movie_4: { starting_price: 0, interval_price: 0, ending_price: 0 }
          },
          is_active: true
        });
        setCurrentStep(1);
        fetchCinemas();
      } else {
        showNotification(data.message || 'Failed to save cinema', 'error');
      }
    } catch (error) {
      console.error('Error saving cinema:', error);
      showNotification('Error saving cinema', 'error');
    }
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingCinema(null);
    setCurrentStep(1);
    setErrors({});
    setFormData({
      cinema_name: '',
      cinema_location: '',
      google_maps_location: '',
      contact_info: { phone: '', email: '' },
      ongoing_movies: {
        movie_1: { name: '', start_date: '', end_date: '', trailer_link: '' },
        movie_2: { name: '', start_date: '', end_date: '', trailer_link: '' },
        movie_3: { name: '', start_date: '', end_date: '', trailer_link: '' },
        movie_4: { name: '', start_date: '', end_date: '', trailer_link: '' }
      },
      upcoming_movies: {
        movie_1: { name: '', trailer_link: '' },
        movie_2: { name: '', trailer_link: '' }
      },
      movie_slot_pricing: {
        movie_1: { starting_price: 0, interval_price: 0, ending_price: 0 },
        movie_2: { starting_price: 0, interval_price: 0, ending_price: 0 },
        movie_3: { starting_price: 0, interval_price: 0, ending_price: 0 },
        movie_4: { starting_price: 0, interval_price: 0, ending_price: 0 }
      },
      is_active: true
    });
  };

  const handleCreateNew = () => {
    setEditingCinema(null);
    setIsModalOpen(true);
    setCurrentStep(1);
  };

  return (
    <div className="cinema-management">
      <CinemaHeader />

      <section id="cinema-cards" className="medpro-cards">
        <div className="container">
          <div className="section-header">
            <h2 className="medpro-cards__title">Cinema Management</h2>
            <p className="medpro-cards__desc">
              Manage all your cinema locations, movie schedules, and advertisement slots from one central dashboard.
            </p>
            <button 
              className="btn btn-primary create-btn"
              onClick={handleCreateNew}
            >
              <i className="fa fa-plus"></i> Add New Cinema
            </button>
          </div>

          {loading ? (
            <div className="loading-container">
              <div className="spinner"></div>
              <p>Loading cinemas...</p>
            </div>
          ) : cinemas.length === 0 ? (
            <div className="no-cinemas">
              <i className="fa fa-film"></i>
              <h3>No Cinemas Found</h3>
              <p>Start by adding your first cinema location.</p>
              <button 
                className="btn btn-primary"
                onClick={handleCreateNew}
              >
                <i className="fa fa-plus"></i> Add Cinema
              </button>
            </div>
          ) : (
            <div className="cinema-grid">
              {cinemas.map((cinema, index) => (
                <CinemaCard 
                  key={cinema._id} 
                  cinema={cinema}
                />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Modal for Create/Edit Cinema */}
      {isModalOpen && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div className="modal-header">
              <h3>{editingCinema ? 'Update Cinema' : 'Add New Cinema'}</h3>
              <button className="close-btn" onClick={handleCloseModal}>×</button>
            </div>

            <div className="modal-body">
              {/* Step indicator */}
              <div className="step-indicator">
                {steps.map((step) => (
                  <div 
                    key={step.id} 
                    className={`step ${currentStep >= step.id ? 'active' : ''} ${currentStep === step.id ? 'current' : ''}`}
                  >
                    <div className="step-number">{step.id}</div>
                    <div className="step-info">
                      <div className="step-title">{step.title}</div>
                      <div className="step-description">{step.description}</div>
                    </div>
                  </div>
                ))}
              </div>

              {/* Form content based on current step */}
              <div className="form-content">
                {currentStep === 1 && (
                  <div className="step-content">
                    <h4>General Details</h4>
                    <div className="form-group">
                      <label>Cinema Name *</label>
                      <input
                        type="text"
                        name="cinema_name"
                        value={formData.cinema_name}
                        onChange={handleInputChange}
                        className={errors.cinema_name ? 'error' : ''}
                        placeholder="Enter cinema name"
                      />
                      {errors.cinema_name && <span className="error-message">{errors.cinema_name}</span>}
                    </div>

                    <div className="form-group">
                      <label>Cinema Location *</label>
                      <input
                        type="text"
                        name="cinema_location"
                        value={formData.cinema_location}
                        onChange={handleInputChange}
                        className={errors.cinema_location ? 'error' : ''}
                        placeholder="Enter cinema location"
                      />
                      {errors.cinema_location && <span className="error-message">{errors.cinema_location}</span>}
                    </div>

                    <div className="form-group">
                      <label>Google Maps Location</label>
                      <input
                        type="url"
                        name="google_maps_location"
                        value={formData.google_maps_location}
                        onChange={handleInputChange}
                        placeholder="https://maps.google.com/..."
                      />
                    </div>

                    <div className="form-row">
                      <div className="form-group">
                        <label>Phone</label>
                        <input
                          type="tel"
                          name="contact_info.phone"
                          value={formData.contact_info.phone}
                          onChange={handleInputChange}
                          placeholder="+94 11 234 5678"
                        />
                      </div>

                      <div className="form-group">
                        <label>Email</label>
                        <input
                          type="email"
                          name="contact_info.email"
                          value={formData.contact_info.email}
                          onChange={handleInputChange}
                          placeholder="info@cinema.com"
                        />
                      </div>
                    </div>

                    <div className="form-group">
                      <label>
                        <input
                          type="checkbox"
                          name="is_active"
                          checked={formData.is_active}
                          onChange={handleInputChange}
                        />
                        Active Cinema
                      </label>
                    </div>
                  </div>
                )}

                {/* Add other steps here - simplified for brevity */}
                {currentStep === 7 && (
                  <div className="step-content">
                    <h4>Review & Submit</h4>
                    <div className="review-content">
                      <h5>Cinema Details</h5>
                      <p><strong>Name:</strong> {formData.cinema_name}</p>
                      <p><strong>Location:</strong> {formData.cinema_location}</p>
                      <p><strong>Status:</strong> {formData.is_active ? 'Active' : 'Inactive'}</p>
                    </div>
                  </div>
                )}
              </div>

              {/* Modal footer */}
              <div className="modal-footer">
                <button 
                  className="btn btn-secondary" 
                  onClick={handlePrevious}
                  disabled={currentStep === 1}
                >
                  Previous
                </button>

                {currentStep < totalSteps ? (
                  <button 
                    className="btn btn-primary" 
                    onClick={handleNext}
                  >
                    Next
                  </button>
                ) : (
                  <button 
                    className="btn btn-primary" 
                    onClick={handleSubmit}
                  >
                    {editingCinema ? 'Update Cinema' : 'Create Cinema'}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Notification */}
      {notification.show && (
        <div className={`custom-notification ${notification.type}`}>
          <div className="notification-content">
            <span className="notification-message">{notification.message}</span>
            <button className="notification-close" onClick={closeNotification}>×</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default CinemaManagement;
